import{_ as t,o as n,c as r,ae as o}from"./chunks/framework.DTQlDYOH.js";const h=JSON.parse('{"title":"Example: Reversi (Othello)","description":"","frontmatter":{},"headers":[],"relativePath":"examples/reversi.md","filePath":"examples/reversi.md"}'),s={name:"examples/reversi.md"};function i(a,e,l,d,c,p){return n(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="example-reversi-othello" tabindex="-1">Example: Reversi (Othello) <a class="header-anchor" href="#example-reversi-othello" aria-label="Permalink to &quot;Example: Reversi (Othello)&quot;">​</a></h1><p>Reversi uses an 8×8 grid, initial four discs in the center, and a <strong>PlaceNew</strong> move that must form a line (current space → existing disc of current player) with opponent discs in between; those get flipped (handled by the engine or follow-up moves).</p><h2 id="entities" tabindex="-1">Entities <a class="header-anchor" href="#entities" aria-label="Permalink to &quot;Entities&quot;">​</a></h2><ul><li><strong>mainGrid</strong> — Grid 8×8.</li><li><strong>disc</strong> — Count <strong>Infinity</strong>, state includes <strong>player</strong> (set when placed).</li></ul><p><strong>initialPlacements</strong> put two discs of player 0 and two of player 1 in the four center cells.</p><h2 id="move" tabindex="-1">Move <a class="header-anchor" href="#move" aria-label="Permalink to &quot;Move&quot;">​</a></h2><p><strong>PlaceNew</strong>: entity is a <strong>disc</strong> with <strong>player</strong> from <strong>ctxPath</strong> <code>currentPlayer</code>. <strong>destination</strong> must be a <strong>Space</strong>, empty, and lie in an <strong>InLine</strong> <strong>sequence</strong>: (current space), then at least one opponent disc, then a disc of the current player (so the line is valid for flipping).</p><p>Turn has <strong>initialMoves</strong> with <strong>PassTurn</strong> when <strong>NoPossibleMoves</strong>.</p><h2 id="end-condition" tabindex="-1">End condition <a class="header-anchor" href="#end-condition" aria-label="Permalink to &quot;End condition&quot;">​</a></h2><p>Game ends when no moves possible; winner is determined by disc count (or similar logic in <strong>endIf</strong> with <strong>Evaluate</strong> / <strong>Every</strong>).</p><p>Full definition: <code>server/reversi.json</code>, <code>server/reversi2.json</code>.</p>',11)])])}const m=t(s,[["render",i]]);export{h as __pageData,m as default};
